package main

import "fmt"

// A dummy function returning a random age
func getAge() int {
    return 20
}

func main() {
    // Create 'age' and immediately check it!
    if age := getAge(); age >= 18 {
        fmt.Println("Adult. Age is:", age)
    } else {
        fmt.Println("Minor. Age is:", age)
    }

    // Uncommenting the line below causes an ERROR because 'age' only exists inside the if/else blocks!
    // fmt.Println(age) 
}
